        import sailpoint.object.ProvisioningPlan;

        trace(logName,"Entering Step: "+wfcontext.getStep().getName());
        addMessage(wfcontext, "Entering Step: "+wfcontext.getStep().getName());
        try{
        ProvisioningPlan plan = enableAllLinks(employee);     
