        try{
        ProvisioningPlan plan = getEntitlementPlan(employee,appname,entitlements,"Remove");       
        launchWorkflow(employee,plan,comments,flow);
        String entitlementsList = Util.listToCsv(entitlements);
        logAuditEvent("Remove Entitlements","entitlements",entitlementsList,comments,employee);
        }catch(Exception e){
        errorMsg = "Exception encountered in: "+wfcontext.getStep().getName()+" "+e;
        log.error(errorMsg);
        }
        log.trace("Exiting Step: "+wfcontext.getStep().getName());
        return;

