        trace(logName,"Entering Step: "+wfcontext.getStep().getName());
        try{
        ProvisioningPlan plan = null;
        String opsconCustomObjectName = "ASCN-Custom-Opsadminconsole";
        String updateAttrKey ="updateAttribute";   

        if(op!=null){
        if(op.equals("Update")){
        if(newValueExpDate != null){
        plan  = getIdentityCubePlan(employee,"ctrexpDt",newValueExpDate);
        }
        else{
        String idAtrr = GeneralUtils.loadCustomMap("updateAttribute", opsconCustomObjectName).get(idAttribute);
        plan = getIdentityCubePlan(employee,idAtrr,newValue);

        }
        }
        else{
        if(idAttribute.equals("Contractor Expiration Date")){
        plan = getIdentityCubePlan(employee,"ctrexpDt",null);
        }
        else{
        String idAtrr = GeneralUtils.loadCustomMap("updateAttribute", opsconCustomObjectName).get(idAttribute);
        plan = getIdentityCubePlan(employee,idAtrr,null);
        }
        }

        launchWorkflow(employee,plan,comments,flow);
        if(newValueExpDate != null){
        logAuditEvent("Update Attribute",idAttribute,newValueExpDate,comments,employee);
        } else {
        logAuditEvent("Update Attribute",idAttribute,newValue,comments,employee);
        }       
        return;
        }
        }catch(Exception e) {
        errorMsg = "Exception encountered in: "+wfcontext.getStep().getName()+" "+e;
        error(logName, errorMsg,e);
        workflow.put("Message", errorMsg);
        handleWorkFlowException(wfcontext, e);
        }
        trace(logName,"Exiting Step: "+wfcontext.getStep().getName());
